import re


class UserTier(Enum):
    GUEST = "guest"
    BASIC = "basic"
    PREMIUM = "premium"
    ADMIN = "admin"


class DiscountType(Enum):
    PERCENTAGE = "percentage"
    FIXED = "fixed"


class CheckoutState(Enum):
    INITIALIZED = "initialized"
    CART_VALIDATED = "cart_validated"
    DISCOUNT_APPLIED = "discount_applied"
    TAX_CALCULATED = "tax_calculated"
    PAYMENT_PROCESSED = "payment_processed"
    ORDER_CREATED = "order_created"


@dataclass
class CartItem:
    product_id: str
    name: str
    price: Decimal
    quantity: int
    max_quantity: int = 100
    available: bool = True


@dataclass
class DiscountCode:
    code: str
    discount_type: DiscountType
    value: Decimal
    min_purchase: Decimal = Decimal('0')
    max_discount: Optional[Decimal] = None
    allowed_tiers: List[UserTier] = field(default_factory=lambda: [UserTier.BASIC, UserTier.PREMIUM, UserTier.ADMIN])
    active: bool = True
    usage_limit: Optional[int] = None
    used_count: int = 0


@dataclass
class User:
    user_id: str
